// Build Backstory activity export query for today's meetings
const tz = 'America/Los_Angeles';
const now = new Date();

// Start of today in PT
const todayStr = now.toLocaleDateString('en-US', { timeZone: tz });
const parts = todayStr.split('/');
const todayMidnight = new Date(parts[2] + '-' + parts[0].padStart(2, '0') + '-' + parts[1].padStart(2, '0') + 'T00:00:00-08:00');
const tomorrowMidnight = new Date(todayMidnight.getTime() + 24 * 3600000);

const query = {
  object: "activity",
  filter: {
    "$and": [
      { attribute: { slug: "ootb_activity_type" }, clause: { "$eq": "meeting" } },
      { attribute: { slug: "ootb_activity_external" }, clause: { "$eq": true } },
      { attribute: { slug: "ootb_activity_timestamp" }, clause: { "$gte": todayMidnight.getTime() } },
      { attribute: { slug: "ootb_activity_timestamp" }, clause: { "$lte": tomorrowMidnight.getTime() } }
    ]
  },
  columns: [
    { slug: "ootb_activity_uid" },
    { slug: "ootb_activity_timestamp" },
    { slug: "ootb_activity_created_at" },
    { slug: "ootb_activity_subject" },
    { slug: "ootb_activity_account" },
    { slug: "ootb_activity_opportunity" },
    { slug: "ootb_activity_participants", variation_id: "ootb_activity_participants_email" },
    { slug: "ootb_activity_participants", variation_id: "ootb_activity_participants_name" },
    { slug: "ootb_activity_participants", variation_id: "ootb_activity_participants_external" },
    { slug: "ootb_activity_duration" },
    { slug: "ootb_activity_sentiment" },
    { slug: "ootb_activity_action_items" },
    { slug: "ootb_activity_key_topics" },
    { slug: "ootb_activity_summary" },
    { slug: "ootb_activity_transcript_status" },
  ],
  sort: [
    { attribute: { slug: "ootb_activity_timestamp" }, direction: "asc" }
  ]
};

return [{ json: { query: JSON.stringify(query) } }];

// Parse CSV and filter for Scott + Shreyas + Frank meetings
const raw = $input.first().json;
const csvText = typeof raw === 'string' ? raw : (raw.data || raw.body || raw.text || '');
const WATCH_EMAILS = ['scott.metcalf@people.ai', 'shreyas.gore@people.ai', 'frank.shawn@people.ai'];

const lines = csvText.trim().split(/\r?\n/).filter(l => l.trim());
if (lines.length < 2) {
  return [{ json: { noMeetings: true } }];
}

// CSV parser that handles both "quoted" and [bracketed] fields
function parseCsvLine(line) {
  const vals = [];
  let i = 0;
  while (i < line.length) {
    if (line[i] === '"') {
      // Quoted field
      i++;
      let val = '';
      while (i < line.length && line[i] !== '"') { val += line[i]; i++; }
      i++; // skip closing quote
      if (i < line.length && line[i] === ',') i++; // skip comma
      vals.push(val);
    } else if (line[i] === '[') {
      // Bracket-enclosed field
      let val = '';
      i++; // skip [
      while (i < line.length && line[i] !== ']') { val += line[i]; i++; }
      i++; // skip ]
      if (i < line.length && line[i] === ',') i++; // skip comma
      vals.push(val);
    } else {
      // Plain field
      let val = '';
      while (i < line.length && line[i] !== ',') { val += line[i]; i++; }
      i++; // skip comma
      vals.push(val.trim());
    }
  }
  return vals;
}

const headers = parseCsvLine(lines[0]);

const now = new Date();
const tz = 'America/Los_Angeles';
const results = [];

for (let i = 1; i < lines.length; i++) {
  const vals = parseCsvLine(lines[i]);
  const row = {};
  headers.forEach((h, idx) => row[h] = vals[idx] || '');

  // Check if any watched email is a participant
  const emails = (row['Activity Participants (Email)'] || '').toLowerCase();
  const isOurs = WATCH_EMAILS.some(e => emails.includes(e));
  if (!isOurs) continue;

  const meetingTime = new Date(row['Activity date'] || '');
  const elapsed = (now - meetingTime) / 3600000;
  const hasEnded = elapsed > 0.25;

  const subject = row['Subject'] || '[no subject]';
  const account = row['Account (name)'] || '';
  const meetingPT = meetingTime.toLocaleTimeString('en-US', { timeZone: tz, hour: 'numeric', minute: '2-digit' });

  // Who from our team
  const nameList = (row['Activity Participants (Name)'] || '').split(';').map(n => n.trim());
  const emailList = (row['Activity Participants (Email)'] || '').split(';').map(e => e.trim());
  const ourPeople = [];
  emailList.forEach((e, idx) => {
    if (WATCH_EMAILS.includes(e.toLowerCase())) {
      ourPeople.push(nameList[idx] || e);
    }
  });

  results.push({
    meetingId: row['Activity'] || '',
    time: meetingPT,
    elapsed: hasEnded ? elapsed.toFixed(1) + 'h ago' : 'upcoming',
    elapsedHours: elapsed,
    hasEnded,
    subject: subject.length > 60 ? subject.substring(0, 57) + '...' : subject,
    account: account || '[unmatched]',
    rep: ourPeople.join(', '),
    needsProbe: hasEnded && !!account,
  });
}

results.sort((a, b) => a.elapsedHours - b.elapsedHours);
results.reverse();

return results.map(m => ({ json: m }));

// Build a targeted probe question for SalesAI
const meeting = $input.first().json;
const account = meeting.account;
const subject = meeting.subject;
const time = meeting.time;

const prompt = `Check the most recent activity for the account "${account}". ` +
  `I had a meeting today at ${time} titled "${subject}". ` +
  `Tell me: does your data include specific discussion topics, action items, or meeting notes from this meeting? ` +
  `Reply with EXACTLY one of these formats:\n` +
  `- ENRICHED: [brief summary of what discussion data you found]\n` +
  `- NOT_ENRICHED: [what data you do have, e.g. "only calendar metadata"]\n` +
  `Be concise. One line only.`;

const systemPrompt = 'You are a data availability checker. Use Backstory MCP tools to look up recent activity for the specified account. ' +
  'Check if the specific meeting has discussion content (topics, action items, notes) or just calendar metadata. ' +
  'Reply in the exact format requested. Be brief and factual.';

return [{ json: { ...meeting, probePrompt: prompt, probeSystem: systemPrompt } }];

// Extract probe result and merge back with meeting data
const input = $input.first().json;
const agentOutput = input.output || input.text || '';

let probeStatus = 'UNKNOWN';
let probeDetail = '';

if (agentOutput.includes('ENRICHED:') && !agentOutput.includes('NOT_ENRICHED')) {
  probeStatus = 'ENRICHED';
  probeDetail = agentOutput.split('ENRICHED:')[1]?.trim() || '';
} else if (agentOutput.includes('NOT_ENRICHED')) {
  probeStatus = 'NOT_ENRICHED';
  probeDetail = agentOutput.split('NOT_ENRICHED:')[1]?.trim() || '';
} else {
  probeDetail = agentOutput.substring(0, 200);
}

// Get meeting data from upstream
const meeting = $('Build Probe Prompt').first().json;

return [{ json: {
  ...meeting,
  probeStatus,
  probeDetail: probeDetail.substring(0, 150),
} }];

// Meeting doesn't need probing (upcoming or no account)
const meeting = $input.first().json;
return [{ json: {
  ...meeting,
  probeStatus: meeting.hasEnded ? 'NO_ACCOUNT' : 'UPCOMING',
  probeDetail: '',
} }];

// Aggregate all meeting probe results into a Slack report
// Collect from both probe paths
// Read accumulated results from static data
const staticData = $getWorkflowStaticData('global');
const allMeetings = staticData.probeResults || [];

// Sort by elapsed (most recent first would be highest elapsed)
allMeetings.sort((a, b) => (b.elapsedHours || 0) - (a.elapsedHours || 0));
allMeetings.reverse(); // earliest first

const now = new Date();
const tz = 'America/Los_Angeles';
const nowPT = now.toLocaleTimeString('en-US', { timeZone: tz, hour: 'numeric', minute: '2-digit' });
const datePT = now.toLocaleDateString('en-US', { timeZone: tz, weekday: 'long', month: 'short', day: 'numeric' });

if (!allMeetings.length) {
  return [{ json: { summary: `:mag: *Meeting Data Monitor* — ${datePT} at ${nowPT} PT\n_No meetings found today._` } }];
}

let summary = `:mag: *Meeting Data Monitor* — ${datePT} at ${nowPT} PT\n`;
summary += `_Tracking: Scott Metcalf, Shreyas Gore, Frank Shawn | ${allMeetings.length} meetings_\n\n`;

summary += ':large_green_circle: transcript data  :large_yellow_circle: no transcript yet  :date: upcoming\n\n';

const statusIcon = {
  'ENRICHED': ':large_green_circle:',
  'NOT_ENRICHED': ':large_yellow_circle:',
  'NO_ACCOUNT': ':large_yellow_circle:',
  'UPCOMING': ':date:',
  'UNKNOWN': ':question:',
};

let enriched = 0, notEnriched = 0, upcoming = 0;

for (const m of allMeetings) {
  const icon = statusIcon[m.probeStatus] || ':question:';

  summary += `${icon} *${m.time}* — ${m.subject} (${m.elapsed})\n`;
  summary += `    _${m.account}_ | ${m.rep || ''}\n`;

  if (m.probeStatus === 'ENRICHED') {
    summary += `    :memo: ${m.probeDetail}\n`;
    enriched++;
  } else if (m.probeStatus === 'NOT_ENRICHED') {
    summary += `    :hourglass: ${m.probeDetail || 'No transcript yet'}\n`;
    notEnriched++;
  } else if (m.probeStatus === 'UPCOMING') {
    upcoming++;
  }
  summary += '\n';
}

summary += `---\n_:large_green_circle: ${enriched} enriched | :large_yellow_circle: ${notEnriched} waiting | :date: ${upcoming} upcoming_`;

return [{ json: { summary } }];

// Reset the results collector for this run
const staticData = $getWorkflowStaticData('global');
staticData.probeResults = [];
return $input.all();

// Append this meeting's probe result to the collector
const staticData = $getWorkflowStaticData('global');
if (!staticData.probeResults) staticData.probeResults = [];
const item = $input.first().json;
staticData.probeResults.push(item);
return [{ json: item }];

